  {"id":"4514","tipo":"multipla","disciplina":"Matematica","tema":"Trigonometria","subtema":"Circunferencia trigonometrica","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"No 2o quadrante, o seno e:","alternativa_a":"Positivo","alternativa_b":"Negativo","alternativa_c":"Zero","alternativa_d":"Indefinido","alternativa_e":"Igual ao coseno","resposta_correta":"a","explicacao":"No 2o quadrante (entre 90 e 180 graus): seno e positivo, coseno e negativo, tangente e negativa.","resposta":""},
  {"id":"4515","tipo":"multipla","disciplina":"Matematica","tema":"Analise Combinatoria","subtema":"Combinacao simples","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O numero de comissoes de 3 pessoas escolhidas de um grupo de 5 pessoas e:","alternativa_a":"10","alternativa_b":"15","alternativa_c":"20","alternativa_d":"60","alternativa_e":"6","resposta_correta":"a","explicacao":"C(5,3) = 5!/(3!*2!) = 120/(6*2) = 120/12 = 10.","resposta":""},
  {"id":"4516","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Espacial","subtema":"Prisma","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O volume de um prisma de base triangular com area da base 12 cm2 e altura 5 cm e:","alternativa_a":"60 cm3","alternativa_b":"30 cm3","alternativa_c":"120 cm3","alternativa_d":"24 cm3","alternativa_e":"36 cm3","resposta_correta":"a","explicacao":"Volume do prisma = Area da base * altura = 12 * 5 = 60 cm3.","resposta":""},
